//  DFScrips, a Quippy cypher querry class, returns a streams.sink.topic.cypher.s12 action result set.
//  The querry has N,MaxN,Dimension, twoSeq as parameters. 
//  Return rows are calculated, then populate a DataFrame.
//  a iterates over dimension          n iterates over range                   b iterates over tConstraint

object QuerryS3T {

import zadscripts.DFScripts
import scala.collection.mutable.ArrayBuffer
import java.math.BigDecimal  // import scala.math.BigDecimal
import org.apache.spark.sql.types.DecimalType
//case class rResult(n:String, maxN:String,dim:String,rowResult:String)  // Both case classes moved to seperate paragraphs.
  def s3TQuerry(rLow:String,rHigh:String,nMax:String,d1:String,d2:String,d3:String,tC:Int):BigDecimal  = {
// case class s3T(dimension:String,Degree:Int,scalar:BigDecimal,index:String,maxIndex:BigDecimal,divisor:BigDecimal,rowCounter:String,result:String)
  val terms = new ArrayBuffer[s3T]()
  val s3 = new DFScripts  
  val s3RS = s3.s3T(rLow,rHigh,nMax,d1,d2,d3,tC)
  while (s3RS.next()) {                            //  maybe shoud be a map.
  val scalar = new BigDecimal(s3RS.getString(3))
  val degree = s3RS.getString(2).toInt
  val divisor = new BigDecimal(s3RS.getString(6))
  val index = new BigDecimal(s3RS.getString(5))
  val indexPower = index.pow(degree)
//  val scalarDiv = scalar/divisor
  val scalarDiv = scalar.divide(divisor)
//  val result =  indexPower * scalarDiv
  val result = indexPower.multiply(scalarDiv)
  //print(result + "    ")
  terms += s3T(s3RS.getString(1),degree,scalar,s3RS.getString(4),index,divisor,s3RS.getString(7),result.toString)
  }
  val termsSeq = terms.toSeq
  //println(termsSeq)
  val resultSeq = termsSeq.map(_.result)           
  val resultSeqBD = resultSeq.collect{ case x:String => new BigDecimal(x) }
  val resultSeqBDD=resultSeqBD.toSeq
  println(resultSeqBDD)                              
 // resultSeqBD.reduce(_+_)
  var sum = new BigDecimal("0")
  for (xs <- resultSeqBD) sum=sum.add(xs)
 // println(sum)
  sum
}

def main(args:Array[String]) {
//  case class rResult(n:String, maxN:String,dim:String,rowResult:BigDecimal)
  val terms = new ArrayBuffer[rResult]()
  val rLow:String = "5"                            
  val rHigh = "5"                                   
  val nMax = "10000"                                 
  val d1 = "4"                                      
  val d2 = "4"                                      
  val d3 = "4"                      
  for( a <- 2 to 5;n <- 2 to 15;b <- 0 to (n-2)) { //aisdim as 2^a.  b is tConstraint  as 2^b
     terms +=rResult(new BigDecimal(2).pow(b).toString(),n.toString(),nMax,new BigDecimal(2).pow(a).toString(),QuerryS3T.s3TQuerry(n.toString,n.toString,nMax,new BigDecimal(2).pow(a).toString(),new BigDecimal(2).pow(a).toString(),new BigDecimal(2).pow(a).toString(),new BigDecimal(2).pow(b).intValue()))
  }
  //  print(terms)
  val termsSeq=terms.toSeq
  val df = spark.createDataFrame(termsSeq)
//val df = spark.createDataSet(termsSeq)     //val dsUsage = spark.createDataset(data)
df.show
z.put("s12DF",df)


}
}
